const TEST_SITE_KEYS = new Set([
  "1x00000000000000000000AA",
  "2x00000000000000000000AB",
  "3x00000000000000000000FF",
]);

function jsString(value) {
  return JSON.stringify(String(value || ""));
}

export function onRequestGet({ env }) {
  const siteKey = String(env.TURNSTILE_SITE_KEY || env.TURNSTILE_PUBLIC_SITE_KEY || "").trim();
  const configured = Boolean(siteKey) && !TEST_SITE_KEYS.has(siteKey);
  const source = siteKey ? (configured ? "env" : "test_key_blocked") : "missing";
  const body = [
    "// Runtime Turnstile config generated by Cloudflare Pages Functions.",
    `window.TURNSTILE_SITE_KEY = ${jsString(siteKey)};`,
    `window.TURNSTILE_SITE_KEY_CONFIGURED = ${configured ? "true" : "false"};`,
    `window.TURNSTILE_SITE_KEY_SOURCE = ${jsString(source)};`,
    "",
  ].join("\n");

  return new Response(body, {
    headers: {
      "content-type": "application/javascript; charset=utf-8",
      "cache-control": "no-store",
    },
  });
}
